368: func DeduplicateTargetObjects(
369: 	namespace string,
370: 	objs []*unstructured.Unstructured,
371: 	infoProvider kubeutil.ResourceInfoProvider,
372: ) ([]*unstructured.Unstructured, []v1alpha1.ApplicationCondition, error) {
373: 	targetByKey := make(map[kubeutil.ResourceKey][]*unstructured.Unstructured)
374: 	for i := range objs {
375: 		obj := objs[i]
376: 		if obj == nil {
377: 			continue
378: 		}
379: 		isNamespaced := kubeutil.IsNamespacedOrUnknown(infoProvider, obj.GroupVersionKind().GroupKind())
380: 		if !isNamespaced {
381: 			obj.SetNamespace("")
382: 		} else if obj.GetNamespace() == "" {
383: 			obj.SetNamespace(namespace)
384: 		}
385: 		key := kubeutil.GetResourceKey(obj)
386: 		if key.Name == "" && obj.GetGenerateName() != "" {
387: 			key.Name = fmt.Sprintf("%s%d", obj.GetGenerateName(), i)
388: 		}
389: 		targetByKey[key] = append(targetByKey[key], obj)
390: 	}
391: 	conditions := make([]v1alpha1.ApplicationCondition, 0)
392: 	result := make([]*unstructured.Unstructured, 0)
393: 	for key, targets := range targetByKey {
394: 		if len(targets) > 1 {
395: 			now := metav1.Now()
396: 			conditions = append(conditions, v1alpha1.ApplicationCondition{
397: 				Type:               v1alpha1.ApplicationConditionRepeatedResourceWarning,
398: 				Message:            fmt.Sprintf("Resource %s appeared %d times among application resources.", key.String(), len(targets)),
399: 				LastTransitionTime: &now,
400: 			})
401: 		}
402: 		result = append(result, targets[len(targets)-1])
403: 	}
404: 
405: 	return result, conditions, nil
406: }
