430: // verifyGnuPGSignature verifies the result of a GnuPG operation for a given git
431: // revision.
432: func verifyGnuPGSignature(revision string, project *v1alpha1.AppProject, manifestInfo *apiclient.ManifestResponse) []v1alpha1.ApplicationCondition {
433: 	now := metav1.Now()
434: 	conditions := make([]v1alpha1.ApplicationCondition, 0)
435: 	// We need to have some data in the verification result to parse, otherwise there was no signature
436: 	if manifestInfo.VerifyResult != "" {
437: 		verifyResult := gpg.ParseGitCommitVerification(manifestInfo.VerifyResult)
438: 		switch verifyResult.Result {
439: 		case gpg.VerifyResultGood:
440: 			// This is the only case we allow to sync to, but we need to make sure signing key is allowed
441: 			validKey := false
442: 			for _, k := range project.Spec.SignatureKeys {
443: 				if gpg.KeyID(k.KeyID) == gpg.KeyID(verifyResult.KeyID) && gpg.KeyID(k.KeyID) != "" {
444: 					validKey = true
445: 					break
446: 				}
447: 			}
448: 			if !validKey {
449: 				msg := fmt.Sprintf("Found good signature made with %s key %s, but this key is not allowed in AppProject",
450: 					verifyResult.Cipher, verifyResult.KeyID)
451: 				conditions = append(conditions, v1alpha1.ApplicationCondition{Type: v1alpha1.ApplicationConditionComparisonError, Message: msg, LastTransitionTime: &now})
452: 			}
453: 		case gpg.VerifyResultInvalid:
454: 			msg := fmt.Sprintf("Found signature made with %s key %s, but verification result was invalid: '%s'",
455: 				verifyResult.Cipher, verifyResult.KeyID, verifyResult.Message)
456: 			conditions = append(conditions, v1alpha1.ApplicationCondition{Type: v1alpha1.ApplicationConditionComparisonError, Message: msg, LastTransitionTime: &now})
457: 		default:
458: 			msg := fmt.Sprintf("Could not verify commit signature on revision '%s', check logs for more information.", revision)
459: 			conditions = append(conditions, v1alpha1.ApplicationCondition{Type: v1alpha1.ApplicationConditionComparisonError, Message: msg, LastTransitionTime: &now})
460: 		}
461: 	} else {
462: 		msg := fmt.Sprintf("Target revision %s in Git is not signed, but a signature is required", revision)
463: 		conditions = append(conditions, v1alpha1.ApplicationCondition{Type: v1alpha1.ApplicationConditionComparisonError, Message: msg, LastTransitionTime: &now})
464: 	}
465: 
466: 	return conditions
467: }
